INSERT INTO english_questions (path_id, topic_id, level, question, options, correct_answer, explanation, difficulty) VALUES
('foundation', 'essential-phrasal-verbs', 'intermediate', 'Choose: the meaning of "wake up".', '["Stop sleeping", "Go to sleep", "Take a nap", "Rest"]', 0, 'Wake up means to stop sleeping and become alert. Common daily phrasal verb.', 'easy'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'What does "get up" mean?', '["Rise from bed or a seat", "Lie down", "Sit down", "Sleep"]', 0, 'Get up means to stand or leave your bed. Morning routine phrasal verb.', 'easy'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'Choose: the meaning of "turn on".', '["Start a device", "Stop a device", "Break a device", "Fix a device"]', 0, 'Turn on means to activate or start something. Common appliance phrasal verb.', 'easy'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'What does "put on" mean?', '["Wear clothes", "Remove clothes", "Wash clothes", "Fold clothes"]', 0, 'Put on means to dress yourself in clothing. Dressing phrasal verb.', 'easy'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'Choose: the meaning of "sit down".', '["Take a seat", "Stand up", "Lie down", "Walk away"]', 0, 'Sit down means to lower yourself into a seated position. Posture phrasal verb.', 'easy'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'What does "come back" mean?', '["Return", "Leave", "Go away", "Depart"]', 0, 'Come back means to return to a place. Movement phrasal verb.', 'easy'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'Choose: the meaning of "look for".', '["Search for", "Find", "Ignore", "Hide"]', 0, 'Look for means to try to find something. Search phrasal verb.', 'easy'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'What does "turn off" mean?', '["Stop a device", "Start a device", "Break a device", "Use a device"]', 0, 'Turn off means to deactivate or stop something. Common appliance phrasal verb.', 'easy'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'Choose: the meaning of "give up".', '["Stop trying", "Keep trying", "Start trying", "Try harder"]', 0, 'Give up means to quit or abandon an effort. Persistence phrasal verb.', 'medium'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'What does "find out" mean?', '["Discover information", "Forget information", "Hide information", "Ignore information"]', 0, 'Find out means to learn or discover something. Discovery phrasal verb.', 'medium'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'Choose: the meaning of "look after".', '["Take care of", "Ignore", "Abandon", "Forget"]', 0, 'Look after means to care for someone or something. Responsibility phrasal verb.', 'medium'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'What does "break down" mean (for machines)?', '["Stop working", "Start working", "Work better", "Work faster"]', 0, 'Break down means to stop functioning. Malfunction phrasal verb.', 'medium'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'Choose: the meaning of "take off" (clothes).', '["Remove clothing", "Put on clothing", "Wash clothing", "Iron clothing"]', 0, 'Take off means to remove what you are wearing. Dressing phrasal verb.', 'medium'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'What does "run out of" mean?', '["Have no more left", "Have too much", "Buy more", "Save some"]', 0, 'Run out of means to use up all of something. Depletion phrasal verb.', 'medium'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'Choose: the meaning of "go on".', '["Continue", "Stop", "Pause", "End"]', 0, 'Go on means to continue or proceed. Action phrasal verb.', 'medium'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'What does "pick up" mean (objects)?', '["Lift something", "Drop something", "Throw something", "Break something"]', 0, 'Pick up means to lift or collect something. Physical action phrasal verb.', 'medium'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'Identify: the difference between "look at" and "look for".', '["\"Look at\" is observe, \"look for\" is search", "They mean the same", "\"Look at\" is search, \"look for\" is observe", "Both mean ignore"]', 0, 'Look at means to observe; look for means to search. Nuanced phrasal verb distinction.', 'hard'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'Choose: the phrasal verb meaning "to resemble a family member".', '["Take after", "Take off", "Take on", "Take over"]', 0, 'Take after means to resemble or act like a family member. Similarity phrasal verb.', 'hard'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'What does "put up with" mean?', '["Tolerate", "Reject", "Avoid", "Escape"]', 0, 'Put up with means to endure or tolerate something unpleasant. Three-word phrasal verb.', 'hard'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'Choose: the phrasal verb that means "to invent or fabricate".', '["Make up", "Make out", "Make for", "Make do"]', 0, 'Make up means to invent a story or excuse. Multiple-meaning phrasal verb (also: reconcile, apply cosmetics).', 'hard'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'Choose: the meaning of "go up".', '["Move higher", "Move lower", "Stay still", "Move sideways"]', 0, 'Go up means to ascend or increase. Direction phrasal verb.', 'easy'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'What does "come in" mean?', '["Enter", "Exit", "Leave", "Stay outside"]', 0, 'Come in means to enter a place. Entry phrasal verb.', 'easy'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'Choose: the meaning of "go out".', '["Leave a place", "Enter a place", "Stay inside", "Return home"]', 0, 'Go out means to exit or leave. Exit phrasal verb (also: socialize outside home).', 'easy'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'What does "walk away" mean?', '["Leave by walking", "Come closer", "Stand still", "Sit down"]', 0, 'Walk away means to depart on foot. Movement phrasal verb.', 'easy'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'Choose: the meaning of "stand up".', '["Rise to feet", "Sit down", "Lie down", "Bend down"]', 0, 'Stand up means to rise from sitting or lying. Posture phrasal verb.', 'easy'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'What does "fall down" mean?', '["Drop to the ground", "Stand up", "Jump up", "Climb up"]', 0, 'Fall down means to collapse or drop. Gravity phrasal verb.', 'easy'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'Choose: the meaning of "move away".', '["Go to a different place", "Stay in same place", "Come closer", "Return home"]', 0, 'Move away means to relocate elsewhere. Relocation phrasal verb.', 'easy'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'What does "run away" mean?', '["Escape quickly", "Approach slowly", "Stand still", "Walk slowly"]', 0, 'Run away means to flee or escape. Escape phrasal verb.', 'easy'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'Choose: the meaning of "get on" (transport).', '["Board a vehicle", "Exit a vehicle", "Drive a vehicle", "Park a vehicle"]', 0, 'Get on means to board public transport (bus, train, plane). Transport phrasal verb.', 'medium'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'What does "drop off" mean?', '["Leave someone at a place", "Pick someone up", "Forget someone", "Meet someone"]', 0, 'Drop off means to deliver or leave someone somewhere. Transport phrasal verb.', 'medium'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'Choose: the meaning of "set off".', '["Begin a journey", "End a journey", "Cancel a journey", "Postpone a journey"]', 0, 'Set off means to start traveling. Journey phrasal verb.', 'medium'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'What does "turn around" mean?', '["Face the opposite direction", "Keep going forward", "Stop moving", "Speed up"]', 0, 'Turn around means to rotate 180 degrees. Direction phrasal verb.', 'medium'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'Choose: the meaning of "pull over" (driving).', '["Stop at roadside", "Drive faster", "Change lanes", "U-turn"]', 0, 'Pull over means to stop your car at the side of the road. Driving phrasal verb.', 'medium'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'What does "catch up with" mean?', '["Reach someone ahead", "Fall behind", "Stay in same place", "Go backward"]', 0, 'Catch up with means to reach someone who is ahead of you. Pursuit phrasal verb.', 'medium'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'Choose: the meaning of "slow down".', '["Reduce speed", "Increase speed", "Stop completely", "Maintain speed"]', 0, 'Slow down means to decrease velocity. Speed phrasal verb.', 'medium'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'What does "head back" mean?', '["Return to starting point", "Go forward", "Stop moving", "Change direction"]', 0, 'Head back means to return to where you came from. Return phrasal verb.', 'medium'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'Identify: the difference between "get in" and "get on".', '["\"Get in\" for cars, \"get on\" for buses/trains", "They are identical", "\"Get in\" for buses, \"get on\" for cars", "Both mean exit"]', 0, 'Get in is for enclosed vehicles (cars, taxis); get on is for public transport (buses, trains, planes). Transport phrasal verb distinction.', 'hard'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'Choose: the phrasal verb meaning "to visit briefly while traveling".', '["Stop by", "Stop over", "Stop off", "Stop at"]', 0, 'Stop by means to visit someone briefly. Casual visit phrasal verb (also: stop in).', 'hard'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'What does "branch off" mean?', '["Separate from main path", "Stay on main path", "Go backwards", "Stop moving"]', 0, 'Branch off means to diverge or separate from a main route. Navigation phrasal verb.', 'hard'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'Choose: the phrasal verb for "to explode or launch suddenly".', '["Take off", "Take on", "Take over", "Take up"]', 0, 'Take off means to leave the ground (planes) or to depart suddenly. Multiple-meaning phrasal verb (also: remove clothes, become successful).', 'hard'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'Choose: the meaning of "hang up".', '["End a phone call", "Start a call", "Continue talking", "Answer a call"]', 0, 'Hang up means to end a telephone conversation. Phone phrasal verb.', 'easy'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'What does "call back" mean?', '["Phone again", "Hang up", "Ignore a call", "Block a number"]', 0, 'Call back means to return a phone call. Phone phrasal verb.', 'easy'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'Choose: the meaning of "speak up".', '["Talk louder", "Talk quietly", "Stop talking", "Whisper"]', 0, 'Speak up means to talk more loudly or express your opinion. Communication phrasal verb.', 'easy'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'What does "shut up" mean (informal)?', '["Stop talking", "Start talking", "Talk louder", "Speak clearly"]', 0, 'Shut up means to be quiet (informal/rude). Silence phrasal verb.', 'easy'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'Choose: the meaning of "ask out".', '["Invite on a date", "Reject someone", "Argue with", "Ignore someone"]', 0, 'Ask out means to invite someone on a romantic date. Dating phrasal verb.', 'easy'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'What does "break up" mean (relationships)?', '["End a relationship", "Start dating", "Get married", "Fall in love"]', 0, 'Break up means to end a romantic relationship. Relationship phrasal verb.', 'easy'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'Choose: the meaning of "get along".', '["Have a good relationship", "Argue constantly", "Ignore each other", "Disagree"]', 0, 'Get along means to have a friendly relationship. Harmony phrasal verb.', 'easy'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'What does "make friends" mean?', '["Form friendships", "Lose friends", "Avoid people", "Argue with people"]', 0, 'Make friends means to become friends with someone. Social phrasal verb.', 'easy'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'Choose: the meaning of "bring up" (topic).', '["Introduce a topic", "Avoid a topic", "Forget a topic", "Ignore a topic"]', 0, 'Bring up means to introduce or mention a subject. Conversation phrasal verb (also: raise children).', 'medium'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'What does "fall out" mean (friends)?', '["Have an argument", "Become closer", "Make peace", "Agree completely"]', 0, 'Fall out means to have a disagreement and stop being friends. Conflict phrasal verb.', 'medium'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'Choose: the meaning of "make up" (after argument).', '["Reconcile", "Continue arguing", "Avoid each other", "Stay angry"]', 0, 'Make up means to become friends again after a fight. Reconciliation phrasal verb.', 'medium'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'What does "stand up for" mean?', '["Defend or support", "Criticize", "Ignore", "Abandon"]', 0, 'Stand up for means to defend someone or something. Support phrasal verb.', 'medium'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'Choose: the meaning of "let down".', '["Disappoint", "Encourage", "Support", "Help"]', 0, 'Let down means to disappoint someone. Disappointment phrasal verb.', 'medium'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'What does "count on" mean?', '["Rely on", "Distrust", "Ignore", "Avoid"]', 0, 'Count on means to depend on or trust someone. Trust phrasal verb.', 'medium'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'Choose: the meaning of "open up" (emotions).', '["Share feelings", "Hide feelings", "Ignore feelings", "Suppress feelings"]', 0, 'Open up means to share your thoughts and feelings. Emotional expression phrasal verb.', 'medium'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'What does "look up to" mean?', '["Admire and respect", "Disrespect", "Ignore", "Look down on"]', 0, 'Look up to means to respect and admire someone. Respect phrasal verb.', 'medium'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'Identify: the difference between "tell off" and "tell on".', '["\"Tell off\" is scold, \"tell on\" is report to authority", "They mean the same", "\"Tell off\" is praise, \"tell on\" is compliment", "Both mean ignore"]', 0, 'Tell off means to reprimand; tell on means to report someones misbehavior. Authority-related phrasal verb pair.', 'hard'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'Choose: the phrasal verb meaning "to gradually stop communicating".', '["Drift apart", "Grow closer", "Stay connected", "Remain friends"]', 0, 'Drift apart means to become less close over time. Relationship distance phrasal verb.', 'hard'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'What does "patch things up" mean?', '["Repair a relationship", "End a relationship", "Avoid someone", "Start an argument"]', 0, 'Patch things up means to resolve a conflict and restore a relationship. Repair phrasal verb.', 'hard'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'Choose: the phrasal verb for "to manipulate or deceive".', '["Take in", "Take on", "Take off", "Take over"]', 0, 'Take in means to deceive or trick someone. Deception phrasal verb (also: understand, provide shelter).', 'hard'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'Choose: the meaning of "work out" (problem).', '["Solve", "Create", "Ignore", "Forget"]', 0, 'Work out means to solve or find a solution. Problem-solving phrasal verb (also: exercise).', 'easy'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'What does "figure out" mean?', '["Understand or solve", "Confuse", "Complicate", "Forget"]', 0, 'Figure out means to understand or solve a problem. Comprehension phrasal verb.', 'easy'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'Choose: the meaning of "clean up".', '["Tidy or organize", "Make messy", "Destroy", "Scatter"]', 0, 'Clean up means to make something tidy. Cleaning phrasal verb.', 'easy'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'What does "throw away" mean?', '["Discard", "Keep", "Save", "Collect"]', 0, 'Throw away means to dispose of something. Disposal phrasal verb.', 'easy'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'Choose: the meaning of "fill in" (forms).', '["Complete", "Delete", "Ignore", "Skip"]', 0, 'Fill in means to complete a form or blank space. Documentation phrasal verb.', 'easy'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'What does "fix up" mean?', '["Repair or renovate", "Break", "Destroy", "Damage"]', 0, 'Fix up means to repair or improve something. Repair phrasal verb.', 'easy'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'Choose: the meaning of "sort out".', '["Organize or resolve", "Mess up", "Confuse", "Complicate"]', 0, 'Sort out means to organize or solve a problem. Organization phrasal verb.', 'easy'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'What does "clear up" mean (confusion)?', '["Clarify", "Confuse", "Complicate", "Obscure"]', 0, 'Clear up means to explain or resolve confusion. Clarification phrasal verb (also: weather improving).', 'easy'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'Choose: the meaning of "deal with".', '["Handle or manage", "Avoid", "Ignore", "Escape"]', 0, 'Deal with means to handle or take action on something. Management phrasal verb.', 'medium'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'What does "carry out" mean?', '["Execute or complete", "Cancel", "Postpone", "Avoid"]', 0, 'Carry out means to perform or complete a task. Execution phrasal verb.', 'medium'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'Choose: the meaning of "come up with".', '["Think of an idea", "Forget an idea", "Reject an idea", "Ignore an idea"]', 0, 'Come up with means to think of or create an idea. Creativity phrasal verb.', 'medium'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'What does "fall through" mean (plans)?', '["Fail to happen", "Succeed", "Proceed as planned", "Improve"]', 0, 'Fall through means when plans fail or dont happen. Failure phrasal verb.', 'medium'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'Choose: the meaning of "cut down on".', '["Reduce", "Increase", "Maintain", "Expand"]', 0, 'Cut down on means to reduce the amount of something. Reduction phrasal verb.', 'medium'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'What does "put off" mean (delay)?', '["Postpone", "Advance", "Do immediately", "Complete early"]', 0, 'Put off means to delay or postpone. Procrastination phrasal verb.', 'medium'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'Choose: the meaning of "get rid of".', '["Eliminate", "Keep", "Collect", "Save"]', 0, 'Get rid of means to dispose of or remove. Elimination phrasal verb.', 'medium'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'What does "go through" mean (examine)?', '["Review carefully", "Skip", "Ignore", "Forget"]', 0, 'Go through means to examine or review something. Review phrasal verb (also: experience difficulty).', 'medium'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'Identify: the difference between "think over" and "think through".', '["\"Think over\" is consider, \"think through\" is analyze fully", "They are identical", "\"Think over\" is ignore, \"think through\" is forget", "Both mean reject"]', 0, 'Think over means to consider carefully; think through means to analyze all aspects completely. Nuanced thinking phrasal verb pair.', 'hard'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'Choose: the phrasal verb meaning "to compensate for".', '["Make up for", "Make out", "Make of", "Make off"]', 0, 'Make up for means to compensate or provide something in return. Compensation phrasal verb.', 'hard'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'What does "pull through" mean?', '["Survive a difficulty", "Give up", "Fail", "Surrender"]', 0, 'Pull through means to recover from illness or survive a difficult situation. Survival phrasal verb.', 'hard'),
('foundation', 'essential-phrasal-verbs', 'intermediate', 'Choose: the phrasal verb for "to investigate thoroughly".', '["Look into", "Look after", "Look for", "Look up"]', 0, 'Look into means to investigate or examine something carefully. Investigation phrasal verb.', 'hard');